/**
 * Mock data for the Operations · Bill of Materials sub-page.
 *
 * Each composition (kit) lists components with required-per-unit count and
 * onHand stock. Derived per component: builds = floor(onHand / required).
 * The composition itself: canProduce = min(builds across components),
 * status = blocked (0) / constrained (<25) / ready (≥25), and bind = the
 * binding component (fewest builds).
 */

export type BomStatus = "ready" | "constrained" | "blocked";

export interface BomComponentRaw {
  name: string;
  /** Required per assembled unit */
  required: number;
  /** Units on hand right now */
  onHand: number;
  /** USD landed per unit */
  landedUnit: number;
}

export interface BomComponent extends BomComponentRaw {
  /** floor(onHand / required) — how many composition units this component supports alone */
  builds: number;
}

export interface BomRaw {
  name: string;
  sku: string;
  hold: boolean;
  holdNote?: string;
  comps: BomComponentRaw[];
}

export interface Bom {
  idx: number;
  name: string;
  sku: string;
  hold: boolean;
  holdNote?: string;
  comps: BomComponent[];
  canProduce: number;
  bind: BomComponent;
  bindName: string;
  costToBuild: number;
  status: BomStatus;
  compN: number;
  statusSort: number;
}

