const STATUS_SORT: Record<BomStatus, number> = { blocked: 0, constrained: 1, ready: 2 };

export const BOMS: Bom[] = RAW.map((b, i) => {
  const comps: BomComponent[] = b.comps.map((c) => ({
    ...c,
    builds: Math.floor(c.onHand / c.required),
  }));
  const canProduce = Math.min(...comps.map((c) => c.builds));
  const bind = comps.reduce((min, c) => (c.builds < min.builds ? c : min), comps[0]);
  const costToBuild = comps.reduce((a, c) => a + c.required * c.landedUnit, 0);
  const status: BomStatus = canProduce === 0 ? "blocked" : canProduce < 25 ? "constrained" : "ready";
  return {
    idx: i,
    name: b.name,
    sku: b.sku,
    hold: b.hold,
    holdNote: b.holdNote,
    comps,
    canProduce,
    bind,
    bindName: bind.name,
    costToBuild,
    status,
    compN: comps.length,
    statusSort: STATUS_SORT[status],
  };
});

