"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge, type BridgePage } from "@/features/bridge/hooks/use-bridge";
import {
  BOMS,
  STATUS_LABEL,
  bomAI,
  type Bom,
  type BomStatus,
} from "@/features/ops/api/ops-bom-data";
import "./bom.css";

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;

type Filter = "all" | BomStatus;
const FILTER_KEYS: Filter[] = ["all", "ready", "constrained", "blocked"];
const FILTER_LABELS = ["All", "Ready", "Constrained", "Blocked"];

const FILTER_FN: Record<Filter, (b: Bom) => boolean> = {
  all: () => true,
  ready: (b) => b.status === "ready",
  constrained: (b) => b.status === "constrained",
  blocked: (b) => b.status === "blocked",
};

type SortKey = "name" | "compN" | "canProduce" | "bindName" | "costToBuild" | "statusSort";

const COLS: Array<{ k: SortKey; l: string; num?: boolean }> = [
  { k: "name", l: "Composition" },
  { k: "compN", l: "Parts", num: true },
  { k: "canProduce", l: "Can produce", num: true },
  { k: "bindName", l: "Limited by" },
  { k: "costToBuild", l: "Cost to build", num: true },
  { k: "statusSort", l: "Status" },
];

const ArrowSvg = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

const prodCls = (n: number) => (n === 0 ? "zero" : n < 25 ? "low" : "ok");

export default function BomPage() {
  const [filterIdx, setFilterIdx] = useState(0);
  const filter: Filter = FILTER_KEYS[filterIdx];

  const [sortKey, setSortKey] = useState<SortKey>("canProduce");
  const [sortDir, setSortDir] = useState<1 | -1>(1);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [rowActionSent, setRowActionSent] = useState<number | null>(null);
  const [panelBridgeSent, setPanelBridgeSent] = useState(false);

  const visible = useMemo(() => {
    const fn = FILTER_FN[filter];
    const arr = BOMS.filter(fn).slice();
    arr.sort((a, b) => {
      if (sortKey === "name" || sortKey === "bindName") {
        return String(a[sortKey]).localeCompare(String(b[sortKey])) * sortDir;
      }
      return (((a[sortKey] as unknown as number) || 0) - ((b[sortKey] as unknown as number) || 0)) * sortDir;
    });
    return arr;
  }, [filter, sortKey, sortDir]);

  const readyCount = BOMS.filter((b) => b.status === "ready").length;
  const constrainedCount = BOMS.filter((b) => b.status === "constrained").length;
  const uniqueComponents = new Set(BOMS.flatMap((b) => b.comps.map((c) => c.name))).size;

  const selected: Bom | null = selectedIdx != null ? BOMS[selectedIdx] : null;
  const onSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setPanelBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(1);
    }
  };
  const { openBridge } = useBridge();
  /** Per execution map §10 Bill of Materials: ready → produce, blocked → reorder. */
  const bomStatusToPage = (s: BomStatus): BridgePage =>
    s === "ready" ? "produce" : "reorder";
  const sendRowAction = (i: number, status: BomStatus) => {
    setRowActionSent(i);
    openBridge("ops", bomStatusToPage(status));
    setTimeout(() => setRowActionSent(null), 1400);
  };
  const sendPanelBridge = (status: BomStatus) => {
    setPanelBridgeSent(true);
    openBridge("ops", bomStatusToPage(status));
    setTimeout(() => setPanelBridgeSent(false), 1700);
  };
  const sendHoldBridge = () => {
    setPanelBridgeSent(true);
    openBridge("ops", "hold");
    setTimeout(() => setPanelBridgeSent(false), 1700);
  };

  return (
    <div className="ops-bom-page">
      <DeptHeader
        dept="ops"
        title="Bill of Materials"
        meta={<><span className="live">Live</span> · How many of each assembled item you can make — and the one component holding it back</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="reorder">Unblock all → Capital Horizon</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={FILTER_LABELS} activeIndex={filterIdx} onChange={setFilterIdx} />

      {/* ───── KPIs ───── */}
      <div className="bom-kpis">
        <div className="bom-kpi">
          <div className="lbl">Compositions</div>
          <div className="val">{BOMS.length}</div>
          <div className="sub">assembled / kitted items</div>
        </div>
        <div className="bom-kpi">
          <div className="lbl">Ready to produce</div>
          <div className="val green">{readyCount}</div>
          <div className="sub">all components in stock</div>
        </div>
        <div className="bom-kpi">
          <div className="lbl">Constrained</div>
          <div className="val loss">{constrainedCount}</div>
          <div className="sub">1 component short each</div>
        </div>
        <div className="bom-kpi">
          <div className="lbl">Unique components</div>
          <div className="val">{uniqueComponents}</div>
          <div className="sub">across all compositions</div>
        </div>
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={bomAI.label} meta={bomAI.meta} cards={bomAI.cards} />

      {/* ───── BoM table + slide-in ───── */}
      <div className="bom-section-label">
        Compositions
        <span className="count">
          {BOMS.length} compositions · {readyCount} ready to produce
        </span>
      </div>

      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          <div className="bom-ledger">
            <div className="bom-head">
              {COLS.map((c) => {
                const active = sortKey === c.k;
                return (
                  <div
                    key={c.k}
                    className={`th${active ? " active" : ""}`}
                    onClick={() => handleSort(c.k)}
                  >
                    {c.l}
                    <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                  </div>
                );
              })}
            </div>

            {visible.length === 0 ? (
              <div className="bom-empty">No compositions in this view</div>
            ) : (
              visible.map((b) => {
                const act = b.status === "ready"
                  ? { label: "Produce", k: "produce" }
                  : { label: "Reorder", k: "reorder" };
                const ready = b.status === "ready";
                return (
                  <div
                    key={b.sku}
                    className={`bom-row${selectedIdx === b.idx ? " sel" : ""}`}
                    onClick={() => onSelect(b.idx)}
                  >
                    <span>
                      <span className="bm-name">{b.name}</span>
                      <span className="bm-sub">{b.sku}</span>
                    </span>
                    <span className="bm-comp">{b.comps.length}</span>
                    <span className={`bm-produce ${prodCls(b.canProduce)}`}>
                      {b.canProduce}
                      <span className="u">units</span>
                    </span>
                    <span>
                      {ready ? (
                        <span className="bm-limit none">
                          <span className="ld" />
                          None — ready
                        </span>
                      ) : (
                        <span className="bm-limit">
                          <span className="ld" />
                          {b.bindName}
                        </span>
                      )}
                    </span>
                    <span className="bm-cost">
                      {fmtUSD(b.costToBuild)}<span className="u">landed</span>
                    </span>
                    <span>
                      <span className={`bm-pill ${b.status}`}>{STATUS_LABEL[b.status]}</span>
                    </span>
                    <button
                      className={`bom-act${rowActionSent === b.idx ? " sent" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        sendRowAction(b.idx, b.status);
                      }}
                    >
                      {rowActionSent === b.idx ? `${act.label} ✓` : (
                        <>
                          {act.label}
                          <ArrowSvg />
                        </>
                      )}
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* ───── Slide-in: constraint breakdown ───── */}
        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="bd-empty">
                <div className="ttl">Constraint breakdown</div>
                <div className="lead">
                  Click a composition to see how many you can build right now, which single component caps that, its true cost to build at landed, and whether to produce or reorder the constraint.
                </div>
              </div>
            ) : (
              <>
                <div className="bd-head">
                  <div>
                    <div className="bd-name">{selected.name}</div>
                    <div className="bd-meta">
                      {selected.sku} · {selected.comps.length} components
                    </div>
                  </div>
                  <button className="bd-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>

                {(() => {
                  const ready = selected.status === "ready";
                  const maxBuilds = Math.max(...selected.comps.map((c) => c.builds));
                  let bh: string;
                  let bb: string;
                  if (ready) {
                    bh = "Ready to produce";
                    bb = `All components in stock. You can build <strong>${selected.canProduce}</strong> units now at <strong>${fmtUSD(selected.costToBuild)}</strong> each (landed).`;
                  } else {
                    const others = selected.comps.filter((c) => c !== selected.bind);
                    const unlock = others.length > 0 ? Math.min(...others.map((c) => c.builds)) : selected.canProduce;
                    const need = (unlock - selected.bind.builds) * selected.bind.required;
                    bh = `Limited by ${selected.bindName}`;
                    bb = `You can build <strong>${selected.canProduce}</strong> now — capped by <strong>${selected.bindName}</strong>. About <strong>${need} more</strong> would unlock <strong>${unlock}</strong> units (the next constraint).`;
                  }
                  return (
                    <>
                      <div className={`bd-bind${ready ? " ready" : ""}`}>
                        <div className="bd-bind-h">{bh}</div>
                        <div className="bd-bind-b" dangerouslySetInnerHTML={{ __html: bb }} />
                      </div>

                      <div className="bd-section">Component constraints · builds each supports</div>
                      {selected.comps.map((c) => {
                        const isBind = c === selected.bind;
                        const w = Math.max((c.builds / maxBuilds) * 100, 3).toFixed(1);
                        const capX = ((selected.canProduce / maxBuilds) * 100).toFixed(1);
                        return (
                          <div key={c.name} className={`bd-comp${isBind ? " bind" : ""}`}>
                            <div className="bd-comp-top">
                              <span className="bd-comp-n">
                                {c.name}
                                <span className="req">{c.required}×/unit</span>
                                {isBind && <span className="bd-comp-tag">binding</span>}
                              </span>
                              <span className="bd-comp-builds">{c.builds} builds</span>
                            </div>
                            <div className="bd-comp-track">
                              <div className="bd-comp-fill" style={{ width: `${w}%` }} />
                              <div className="bd-comp-cap" style={{ left: `${capX}%` }} />
                            </div>
                          </div>
                        );
                      })}

                      <div className="bd-cost">
                        <div>
                          <div className="cl">Cost to build · landed</div>
                        </div>
                        <div style={{ textAlign: "right" }}>
                          <div className="cv">{fmtUSD(selected.costToBuild)}</div>
                          <div className="bd-cost-sub">per unit · rolled from components</div>
                        </div>
                      </div>

                      <div className="bd-actions">
                        {ready ? (
                          <>
                            <button
                              className={`bd-btn primary${panelBridgeSent ? " sent" : ""}`}
                              onClick={() => sendPanelBridge(selected.status)}
                            >
                              {panelBridgeSent
                                ? `Produce ${selected.canProduce} sent ✓`
                                : `Produce ${selected.canProduce} → Bridge`}
                            </button>
                            {selected.hold && (
                              <>
                                <div className="bd-hold-note">
                                  <strong>Hold suggested:</strong> {selected.holdNote}. Producing now spends a component better used elsewhere.
                                </div>
                                <button
                                  className="bd-btn ghost"
                                  onClick={sendHoldBridge}
                                >
                                  Hold for now
                                </button>
                              </>
                            )}
                          </>
                        ) : (
                          <>
                            <button
                              className={`bd-btn primary${panelBridgeSent ? " sent" : ""}`}
                              onClick={() => sendPanelBridge(selected.status)}
                            >
                              {panelBridgeSent
                                ? `Reorder ${selected.bindName} sent ✓`
                                : `Reorder ${selected.bindName} → Bridge`}
                            </button>
                            {selected.canProduce > 0 && (
                              <button
                                className={`bd-btn ghost${panelBridgeSent ? " sent" : ""}`}
                                onClick={() => {
                                  setPanelBridgeSent(true);
                                  openBridge("ops", "produce");
                                  setTimeout(() => setPanelBridgeSent(false), 1700);
                                }}
                              >
                                {panelBridgeSent
                                  ? `Produce ${selected.canProduce} now ✓`
                                  : `Produce ${selected.canProduce} now anyway`}
                              </button>
                            )}
                          </>
                        )}
                      </div>
                    </>
                  );
                })()}
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
